import{_ as t,o as a,c as i,aj as n}from"./chunks/framework.Co0EVkx3.js";const p=JSON.parse('{"title":"Addon Development","description":"","frontmatter":{},"headers":[],"relativePath":"en/posts/docs/addon/index.md","filePath":"en/posts/docs/addon/index.md","lastUpdated":1773836152000}'),o={name:"en/posts/docs/addon/index.md"};function r(l,e,d,s,c,m){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="addon-development" tabindex="-1">Addon Development <a class="header-anchor" href="#addon-development" aria-label="Permalink to “Addon Development”">​</a></h1><p>Welcome to the AnvilCraft Addon Development documentation! This section will guide you through creating your own AnvilCraft addon mod.</p><h2 id="what-is-an-addon-mod" tabindex="-1">What is an Addon Mod? <a class="header-anchor" href="#what-is-an-addon-mod" aria-label="Permalink to “What is an Addon Mod?”">​</a></h2><p>An addon mod is an extension built on top of the AnvilCraft core mod, allowing developers and creators to:</p><ul><li>Add new items and blocks</li><li>Create custom recipes</li><li>Extend existing AnvilCraft mechanics</li><li>Integrate with other mods</li><li>Contribute new content to the AnvilCraft ecosystem</li></ul><h2 id="why-create-an-addon-mod" tabindex="-1">Why Create an Addon Mod? <a class="header-anchor" href="#why-create-an-addon-mod" aria-label="Permalink to “Why Create an Addon Mod?”">​</a></h2><ol><li><strong>Extend Functionality</strong>: Add new content without modifying the core mod</li><li><strong>Maintain Compatibility</strong>: Addon mods work well with the main AnvilCraft mod and other addons</li><li><strong>Community Contribution</strong>: Share your creativity and ideas with the AnvilCraft community</li><li><strong>Learning Opportunity</strong>: Gain deeper understanding of Minecraft mod development through practice</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><p>Before you begin development, you need to:</p><ol><li>Be familiar with the Java programming language</li><li>Understand vanilla Minecraft mechanics</li><li>Grasp basic mod development concepts</li><li>Have your development environment ready (JDK 21, IDE, etc.)</li></ol><h2 id="development-overview" tabindex="-1">Development Overview <a class="header-anchor" href="#development-overview" aria-label="Permalink to “Development Overview”">​</a></h2><h3 id="basic-development" tabindex="-1">Basic Development <a class="header-anchor" href="#basic-development" aria-label="Permalink to “Basic Development”">​</a></h3><ol><li><a href="./01_environment.html">Environment Setup</a> - Configure your development environment</li><li><a href="./02_create_item.html">Creating Your First Item</a> - Learn basic item registration</li><li><a href="./03_create_block.html">Creating Your First Block</a> - Learn basic block registration</li></ol><h3 id="advanced-development" tabindex="-1">Advanced Development <a class="header-anchor" href="#advanced-development" aria-label="Permalink to “Advanced Development”">​</a></h3><ol start="4"><li><a href="./04_create_entity.html">Entity Registration</a> - Learn how to create custom entities</li><li><a href="./05_create_block_entity.html">Block Entity Development</a> - Create blocks with logic</li><li><a href="./06_data_generation.html">Data Generators</a> - Automatically generate game resources</li><li><a href="./07_config.html">Configuration System</a> - Create mod configuration files</li><li><a href="./08_recipe_integration.html">Recipe System Integration</a> - Integrate with AnvilCraft recipe system</li><li><a href="./09_event_system.html">Event System</a> - Use the NeoForge event system</li><li><a href="./10_resources.html">Resources and Localization</a> - Manage textures, models, and language files</li><li><a href="./11_networking.html">Networking</a> - Implement client-server communication</li></ol><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to “Tech Stack”">​</a></h2><p>AnvilCraft addon mod development primarily uses the following technologies:</p><ul><li><strong>Java 21</strong> - Programming language</li><li><strong>Gradle</strong> - Build tool</li><li><strong>Registrum</strong> - Content registration system (Registration API provided by AnvilLib, improved from Registrate)</li><li><strong>NeoForge</strong> - Mod loader API</li><li><strong>Lombok</strong> - Simplifies Java code writing</li></ul><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to “Best Practices”">​</a></h2><ul><li>Follow AnvilCraft&#39;s design language and style</li><li>Maintain consistency with vanilla Minecraft</li><li>Make full use of the APIs provided by AnvilCraft</li><li>Write clear documentation and comments</li><li>Perform thorough testing</li></ul><p>Ready to start your addon development journey? Let&#39;s begin with <a href="./01_environment.html">Environment Setup</a>!</p>',21)])])}const g=t(o,[["render",r]]);export{p as __pageData,g as default};
